import java.util.*;
public class Inorder {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<Integer> inorder(TreeNode root){
        List<Integer> res=new ArrayList<>();dfs(root,res);return res;}
    static void dfs(TreeNode n,List<Integer> l){
        if(n==null)return;dfs(n.left,l);l.add(n.val);dfs(n.right,l);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.right=new TreeNode(2);r.right.left=new TreeNode(3);
        System.out.println(inorder(r));  // [1,3,2]
        System.out.println("L-N-R. BST inorder = sorted ascending.");
    }
}

import java.util.*;
public class InorderIter {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<Integer> inorder(TreeNode root){
        List<Integer> res=new ArrayList<>();Deque<TreeNode> st=new ArrayDeque<>();
        TreeNode cur=root;
        while(cur!=null||!st.isEmpty()){
            while(cur!=null){st.push(cur);cur=cur.left;}
            cur=st.pop();res.add(cur.val);cur=cur.right;}
        return res;
    }
    public static void main(String[] a){
        TreeNode r=new TreeNode(4);r.left=new TreeNode(2);r.right=new TreeNode(6);
        r.left.left=new TreeNode(1);r.left.right=new TreeNode(3);
        System.out.println(inorder(r));  // [1,2,3,4,6]
        System.out.println("O(n) O(h) — push lefts, pop then go right");
    }
}

import java.util.*;
public class LevelOrd {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<List<Integer>> levelOrder(TreeNode root){
        List<List<Integer>> res=new ArrayList<>();if(root==null)return res;
        Queue<TreeNode> q=new ArrayDeque<>();q.offer(root);
        while(!q.isEmpty()){
            int sz=q.size();List<Integer> lvl=new ArrayList<>();
            for(int i=0;i<sz;i++){
                TreeNode n=q.poll();lvl.add(n.val);
                if(n.left!=null)q.offer(n.left);
                if(n.right!=null)q.offer(n.right);}
            res.add(lvl);}
        return res;
    }
    public static void main(String[] a){
        TreeNode r=new TreeNode(3);r.left=new TreeNode(9);r.right=new TreeNode(20);
        r.right.left=new TreeNode(15);r.right.right=new TreeNode(7);
        System.out.println(levelOrder(r));
        System.out.println("[[3],[9,20],[15,7]] — size snapshot per level");
    }
}

public class MaxDepth {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static int maxDepth(TreeNode r){
        return r==null?0:1+Math.max(maxDepth(r.left),maxDepth(r.right));}
    public static void main(String[] a){
        TreeNode r=new TreeNode(3);r.left=new TreeNode(9);r.right=new TreeNode(20);
        r.right.left=new TreeNode(15);r.right.right=new TreeNode(7);
        System.out.println(maxDepth(r));  // 3
        System.out.println(maxDepth(null)); // 0
        System.out.println("O(n) postorder: 1+max(left,right)");
    }
}

import java.util.*;
public class RightView {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<Integer> rightSideView(TreeNode root){
        List<Integer> res=new ArrayList<>();if(root==null)return res;
        Queue<TreeNode> q=new ArrayDeque<>();q.offer(root);
        while(!q.isEmpty()){
            int sz=q.size();
            for(int i=0;i<sz;i++){
                TreeNode n=q.poll();
                if(i==sz-1)res.add(n.val);
                if(n.left!=null)q.offer(n.left);
                if(n.right!=null)q.offer(n.right);}}
        return res;
    }
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(3);
        r.left.right=new TreeNode(5);r.right.right=new TreeNode(4);
        System.out.println(rightSideView(r)); // [1,3,4]
        System.out.println("Last node (i==sz-1) per BFS level = right side");
    }
}

import java.util.*;
public class Zigzag {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<List<Integer>> zigzag(TreeNode root){
        List<List<Integer>> res=new ArrayList<>();if(root==null)return res;
        Queue<TreeNode> q=new ArrayDeque<>();q.offer(root);boolean lr=true;
        while(!q.isEmpty()){
            int sz=q.size();LinkedList<Integer> lvl=new LinkedList<>();
            for(int i=0;i<sz;i++){
                TreeNode n=q.poll();
                if(lr)lvl.addLast(n.val);else lvl.addFirst(n.val);
                if(n.left!=null)q.offer(n.left);
                if(n.right!=null)q.offer(n.right);}
            res.add(lvl);lr=!lr;}
        return res;
    }
    public static void main(String[] a){
        TreeNode r=new TreeNode(3);r.left=new TreeNode(9);r.right=new TreeNode(20);
        r.right.left=new TreeNode(15);r.right.right=new TreeNode(7);
        System.out.println(zigzag(r));
        System.out.println("addFirst/addLast toggle by level direction flag");
    }
}

public class SymTree {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static boolean isSymmetric(TreeNode r){return r==null||mirror(r.left,r.right);}
    static boolean mirror(TreeNode l,TreeNode r){
        if(l==null&&r==null)return true;
        if(l==null||r==null||l.val!=r.val)return false;
        return mirror(l.left,r.right)&&mirror(l.right,r.left);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(2);
        r.left.left=new TreeNode(3);r.left.right=new TreeNode(4);
        r.right.left=new TreeNode(4);r.right.right=new TreeNode(3);
        System.out.println(isSymmetric(r)); // true
        TreeNode r2=new TreeNode(1);r2.left=new TreeNode(2);r2.right=new TreeNode(2);
        r2.left.right=new TreeNode(3);r2.right.right=new TreeNode(3);
        System.out.println(isSymmetric(r2)); // false
        System.out.println("mirror(l.left,r.right) && mirror(l.right,r.left)");
    }
}

public class Diameter {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static int max=0;
    static int dfs(TreeNode r){
        if(r==null)return 0;
        int l=dfs(r.left),ri=dfs(r.right);
        max=Math.max(max,l+ri);
        return 1+Math.max(l,ri);}
    static int diameter(TreeNode r){max=0;dfs(r);return max;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(3);
        r.left.left=new TreeNode(4);r.left.right=new TreeNode(5);
        System.out.println(diameter(r)); // 3
        System.out.println("Diameter = max(left_h + right_h) across all nodes");
        System.out.println("O(n) — update global max at each node, return height");
    }
}

import java.util.*;
public class AllTraversals {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<Integer> pre(TreeNode n){List<Integer> r=new ArrayList<>();preH(n,r);return r;}
    static void preH(TreeNode n,List<Integer> r){if(n==null)return;r.add(n.val);preH(n.left,r);preH(n.right,r);}
    static List<Integer> in(TreeNode n){List<Integer> r=new ArrayList<>();inH(n,r);return r;}
    static void inH(TreeNode n,List<Integer> r){if(n==null)return;inH(n.left,r);r.add(n.val);inH(n.right,r);}
    static List<Integer> post(TreeNode n){List<Integer> r=new ArrayList<>();postH(n,r);return r;}
    static void postH(TreeNode n,List<Integer> r){if(n==null)return;postH(n.left,r);postH(n.right,r);r.add(n.val);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(3);
        r.left.left=new TreeNode(4);r.left.right=new TreeNode(5);
        System.out.println("Pre (N-L-R): "+pre(r));  // [1,2,4,5,3]
        System.out.println("In  (L-N-R): "+in(r));   // [4,2,5,1,3]
        System.out.println("Post(L-R-N): "+post(r)); // [4,5,2,3,1]
        System.out.println("Pre=copy tree, In=sorted(BST), Post=delete tree");
    }
}

public class FlattenTree {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static void flatten(TreeNode root){
        TreeNode cur=root;
        while(cur!=null){
            if(cur.left!=null){
                TreeNode pre=cur.left;
                while(pre.right!=null)pre=pre.right; // rightmost of left subtree
                pre.right=cur.right; // connect right subtree to rightmost
                cur.right=cur.left;  // move left subtree to right
                cur.left=null;}
            cur=cur.right;}}
    static String str(TreeNode r){StringBuilder sb=new StringBuilder();while(r!=null){sb.append(r.val);if(r.right!=null)sb.append("-");r=r.right;}return sb.toString();}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(5);
        r.left.left=new TreeNode(3);r.left.right=new TreeNode(4);r.right.right=new TreeNode(6);
        flatten(r);System.out.println(str(r)); // 1-2-3-4-5-6
        System.out.println("O(n) O(1): connect leftmost path then move on");
    }
}

import java.util.*;
public class T1Synth {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<Integer> inIter(TreeNode root){List<Integer> res=new ArrayList<>();Deque<TreeNode> st=new ArrayDeque<>();TreeNode c=root;while(c!=null||!st.isEmpty()){while(c!=null){st.push(c);c=c.left;}c=st.pop();res.add(c.val);c=c.right;}return res;}
    static List<List<Integer>> level(TreeNode root){List<List<Integer>> res=new ArrayList<>();if(root==null)return res;Queue<TreeNode> q=new ArrayDeque<>();q.offer(root);while(!q.isEmpty()){int sz=q.size();List<Integer> lvl=new ArrayList<>();for(int i=0;i<sz;i++){TreeNode n=q.poll();lvl.add(n.val);if(n.left!=null)q.offer(n.left);if(n.right!=null)q.offer(n.right);}res.add(lvl);}return res;}
    static int depth(TreeNode r){return r==null?0:1+Math.max(depth(r.left),depth(r.right));}
    public static void main(String[] a){
        TreeNode r=new TreeNode(3);r.left=new TreeNode(1);r.right=new TreeNode(2);
        System.out.println("inorder="+inIter(r));
        System.out.println("levels="+level(r).size());
        System.out.println("depth="+depth(r));
        boolean ok=inIter(r).toString().equals("[1, 3, 2]")&&level(r).size()==2&&depth(r)==2;
        System.out.println("All pass: "+ok);
    }
}

import java.util.*;
public class T1Final {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<Integer> in(TreeNode r){List<Integer> res=new ArrayList<>();Deque<TreeNode> st=new ArrayDeque<>();TreeNode c=r;while(c!=null||!st.isEmpty()){while(c!=null){st.push(c);c=c.left;}c=st.pop();res.add(c.val);c=c.right;}return res;}
    static int depth(TreeNode r){return r==null?0:1+Math.max(depth(r.left),depth(r.right));}
    static int diam(TreeNode r){int[]m={0};dh(r,m);return m[0];}
    static int dh(TreeNode r,int[]m){if(r==null)return 0;int l=dh(r.left,m),ri=dh(r.right,m);m[0]=Math.max(m[0],l+ri);return 1+Math.max(l,ri);}
    static boolean sym(TreeNode r){return r==null||mir(r.left,r.right);}
    static boolean mir(TreeNode l,TreeNode r){if(l==null&&r==null)return true;if(l==null||r==null||l.val!=r.val)return false;return mir(l.left,r.right)&&mir(l.right,r.left);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(2);
        r.left.left=new TreeNode(3);r.right.right=new TreeNode(3);
        System.out.println("in="+in(of(4,2,6,1,3)));
        System.out.println("depth="+depth(r));
        System.out.println("sym="+sym(r));
        System.out.println("diam="+diam(of(1,2,3,4,5)));
        boolean ok=depth(r)==3&&sym(r)&&diam(of(1,2,3,4,5))==3;
        System.out.println("All pass: "+ok);
    }
    static TreeNode of(int...vs){TreeNode d=new TreeNode(0);Queue<TreeNode> q=new ArrayDeque<>();q.offer(new TreeNode(vs[0]));TreeNode root=q.peek();for(int i=1;i<vs.length;i+=2){TreeNode n=q.poll();if(i<vs.length){n.left=new TreeNode(vs[i]);q.offer(n.left);}if(i+1<vs.length){n.right=new TreeNode(vs[i+1]);q.offer(n.right);}}return root;}
}
